const items = $input.all();
return items.map(item => {
  const referrer = (item.json.referrer || '').toLowerCase();
  let ai_source = 'unknown';

  if (referrer.includes('chatgpt.com') || referrer.includes('chat.openai.com')) {
    ai_source = 'chatgpt';
  } else if (referrer.includes('perplexity.ai')) {
    ai_source = 'perplexity';
  } else if (referrer.includes('claude.ai') || referrer.includes('anthropic.com')) {
    ai_source = 'claude';
  } else if (referrer.includes('gemini.google.com') || referrer.includes('bard.google.com')) {
    ai_source = 'gemini';
  } else if (referrer.includes('copilot.microsoft.com') || referrer.includes('bing.com/chat')) {
    ai_source = 'copilot';
  }

  return {
    json: {
      ...item.json,
      ai_source
    }
  };
});
